    meta: { requiresAuth: true },
  },
  {
    path: '/article/:slug',
    name: 'article',
    component: () => import('src/views/ArticleView.vue'),
  },
  {
    path: '/article/create',
    name: 'create-article',
    component: () => import('src/views/CreateArticleView.vue'),
    meta: { requiresAuth: true },
  },
  {
    path: '/article/:slug/edit',
    name: 'edit-article',
    component: () => import('src/views/EditArticleView.vue'),
    meta: { requiresAuth: true },
  },
  {
    path: '/:pathMatch(.*)*',
    name: 'not-found',
    component: () => import('src/views/NotFoundView.vue'),
  },
]

export const createAppRouter = () => {
  const router = createRouter({
    history: createWebHistory(),
    routes,
  })

  router.beforeEach((to) => {
    const { isAuthenticated } = storeToRefs(useUserStore())

    if (to.meta.requiresAuth && !isAuthenticated.value) {
      return { name: 'login' }
    }

    if (to.meta.requiresGuest && isAuthenticated.value) {
      return { name: 'global-feed' }
    }
  })

  return router
}
